// Extract Ghost webhook payload
const data = $input.first().json;

// Handle manual trigger or empty payload
if (!data || Object.keys(data).length === 0) {
  throw new Error('Webhook triggered with no data. If testing manually, ensure you have provided a sample Ghost payload.');
}

// Ghost 5.x Structure: { "post": { "current": { ... }, "previous": { ... } } }
// We also handle flattened or nested structures for maximum compatibility
let post = data.post?.current || data.current || data.post || data.body?.post?.current || data.body?.post || data;
let previous = data.post?.previous || data.previous || data.body?.post?.previous;

if (!post || !post.id || !post.url) {
  console.error('Payload Structure Error. Keys found:', Object.keys(data).join(', '));
  if (data.post) console.error('Post keys:', Object.keys(data.post).join(', '));
  throw new Error(`Ghost webhook payload missing post.current.id or url. Found keys: ${Object.keys(data).join(', ')}`);
}

// Post-processing and status check
post.slug = post.slug || `post-${post.id}`;
post.title = post.title || 'Untitled Post';

// Process if published or updated
const status = post.status?.toLowerCase();
if (status && status !== 'published' && status !== 'updated') {
  return [{ json: { skip: true, reason: `Post status is '${status}' (expected published or updated)` } }];      
}

// Helper to remove audio player from html/lexical for comparison
const stripAudioPlayer = (str) => {
    if (!str) return '';
    if (typeof str !== 'string') str = JSON.stringify(str);
    return str.replace(/<!--kg-card-begin: html-->[\s\S]*?id=["']gn-audio-embed["'][\s\S]*?<!--kg-card-end: html-->/gi, '')
              .replace(/<figure[^>]*>[\s\S]*?id=["']gn-audio-embed["'][\s\S]*?<\/figure>/gi, '')
              .replace(/<div[^>]*id=["']gn-audio-embed["'][^>]*>[\s\S]*?<\/div>/gi, '')
              .replace(/Listen to article/gi, '')
              .replace(/Speed/gi, '')
              .replace(/\s+/g, ' ')
              .trim();
};

// Edge Case: Check if this is an update and if relevant content actually changed
if (previous && Object.keys(previous).length > 0) {
  // If it's a transition to 'published' from another status (e.g., 'draft'), it's a new publish. We should process it.
  const isNewlyPublished = previous.hasOwnProperty('status') && previous.status !== 'published' && status === 'published';

  // Check if title or slug changed
  const metaChanged = previous.hasOwnProperty('title') || previous.hasOwnProperty('slug');

  // Check if content changed, ignoring the audio player embed itself (prevent infinite loops from our own updates)
  let contentChanged = false;
  const contentFields = ['html', 'mobiledoc', 'lexical', 'plaintext'];

  for (const field of contentFields) {
      if (previous.hasOwnProperty(field)) {
          const oldVal = stripAudioPlayer(previous[field]);
          const newVal = stripAudioPlayer(post[field]);
          if (oldVal !== newVal) {
              contentChanged = true;
              break;
          }
      }
  }

  if (!isNewlyPublished && !metaChanged && !contentChanged) {
    return [{ json: { skip: true, reason: 'Post updated, but no relevant content (title, content, slug) changed. (Ignored audio player embed changes to prevent loops)' } }];
  }
}

// Extract hostname for site-specific logic
let siteBase = '';
let hostname = 'unknown-site';
try {
  const urlMatch = post.url.match(/^(https?:\/\/([^\/]+))/);
  if (urlMatch) {
    siteBase = urlMatch[1];
    hostname = urlMatch[2];
  }
} catch (e) {
  console.error('Failed to parse URL:', post.url);
}

const siteSlug = hostname.replace(/\./g, '-');
// Use backfill_job_id from payload when provided (backfill script passes a deterministic ID
// so it can poll for completion). For live Ghost publishes, generate a timestamp-based ID
// so content updates always get a fresh TTS job instead of hitting the completed cache.
const jobId = data.backfill_job_id || data.body?.backfill_job_id || `${siteSlug}-pid-${post.id}-${post.slug}-${Date.now()}`;

return [{
  json: {
    skip: false,
    postId: post.id,
    postSlug: post.slug,
    postTitle: post.title,
    postUrl: post.url,
    siteBase,
    siteSlug,
    hostname,
    jobId,
    timestamp: new Date().toISOString()
  }
}];

const item = $input.first().json;
const post = item.posts?.[0];

if (!post) {
  throw new Error('Could not fetch article from Ghost API');
}

// Clean up the plaintext
let text = post.plaintext || '';
text = text.replace(/\n{3,}/g, '\n\n').trim();

if (!text) {
  throw new Error('Post has no plaintext content - cannot generate narration');
}

// Get metadata from previous node
const meta = $('Extract Post Metadata').first().json;

return [{
  json: {
    jobId: meta.jobId,
    siteSlug: meta.siteSlug,
    postTitle: post.title,
    postSlug: post.slug,
    articleText: text,
    wordCount: text.split(/\s+/).length
  }
}];

let script = $input.first().json.choices?.[0]?.message?.content || '';

if (!script) {
  throw new Error('LLM returned empty narration');
}

// Strip Qwen3 thinking blocks if present
script = script.replace(/<think>[\s\S]*?<\/think>/gi, '');

// Strip common LLM meta-commentary lines that appear before the actual content.
// These are lines where the model talks ABOUT the task rather than doing it.
const metaPatterns = [
  /^(okay|alright|sure|certainly|of course)[,.].*$/im,
  /^(the user wants|the user is asking|i need to|i should|i will|i'll|let me|let's|first,? i|now,? i).*$/im,
  /^(converting|rewriting|transforming|here is|here's|below is|the following|this is).*?(narration|script|podcast|article|text).*$/im,
  /^(key (rules|points|things)|important:|note:|rule \d)/im,
  /^(I have (converted|rewritten|created)|This is (a|the) (narration|script)).*$/im,
  /^Here is the (narration|script|podcast version).*$/im
];

// Split into lines, filter out meta-commentary, rejoin
const lines = script.split('\n');
const cleanLines = lines.filter(line => {
  const trimmed = line.trim();
  if (!trimmed) return true; // keep blank lines
  return !metaPatterns.some(pattern => pattern.test(trimmed));
});

script = cleanLines.join('\n').trim();

// NEW: Strip remaining markdown characters that can cause hallucination/stuttering in TTS
script = script.replace(/[#*_~>]/g, '');

// Remove any leading/trailing whitespace or blank lines
script = script.replace(/^\s+/, '').replace(/\s+$/, '');

if (!script) {
  throw new Error('Narration text is empty after cleanup - LLM may have only returned meta-commentary');
}

// Get context from previous nodes
const meta = $('Prepare Article Text').first().json;

return [{
  json: {
    jobId: meta.jobId,
    siteSlug: meta.siteSlug,
    postTitle: meta.postTitle,
    postSlug: meta.postSlug,
    narrationText: script,
    wordCount: script.split(/\s+/).length
  }
}];

const result = $input.first().json;
console.log('TTS Job submitted:', result);
if (result.error || result.detail) {
  throw new Error('TTS service rejected job: ' + (result.error || result.detail));
}
return [{ json: { success: true, ...result } }];
